/*
 * Cloud Data Encryption - AES-256-CBC Implementation
 * Demonstrates encryption at rest for cloud storage (e.g., EBS, S3)
 * Compile: gcc -o encryption encryption.c -lssl -lcrypto
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <openssl/evp.h>
#include <openssl/rand.h>

#define AES_KEY_LEN 32 /* 256 bits */
#define AES_IV_LEN 16 /* 128 bits for CBC mode */
#define BUFFER_SIZE 1024

/* Function: Generate cryptographically secure random bytes */
int generate_random_bytes(unsigned char *buffer, int length) {
 if (RAND_bytes(buffer, length) != 1) {
 fprintf(stderr, "Error: Failed to generate random bytes\n");
 return -1;
 }
 return 0;
}

/* Function: AES-256-CBC Encryption */
/* Simulates server-side encryption like AWS S3 SSE */
int aes_encrypt(unsigned char *plaintext, int plaintext_len,
 unsigned char *key, unsigned char *iv,
 unsigned char **ciphertext) {

 EVP_CIPHER_CTX *ctx = EVP_CIPHER_CTX_new();
 if (!ctx) {
 fprintf(stderr, "Error: Failed to create cipher context\n");
 return -1;
 }

 int len = 0;
 int ciphertext_len = 0;

 /* Allocate output buffer (plaintext + block size) */
 *ciphertext = malloc(plaintext_len + AES_IV_LEN);
 if (!*ciphertext) {
 EVP_CIPHER_CTX_free(ctx);
 return -1;
 }

 /* Initialize encryption operation */
 if (EVP_EncryptInit_ex(ctx, EVP_aes_256_cbc(), NULL, key, iv) != 1) {
 fprintf(stderr, "Error: Encryption init failed\n");
 free(*ciphertext);
 EVP_CIPHER_CTX_free(ctx);
 return -1;
 }

 /* Encrypt the plaintext */
 if (EVP_EncryptUpdate(ctx, *ciphertext, &len, plaintext, plaintext_len) != 1) {
 fprintf(stderr, "Error: Encryption update failed\n");
 free(*ciphertext);
 EVP_CIPHER_CTX_free(ctx);
 return -1;
 }
 ciphertext_len = len;

 /* Finalize encryption (handle padding) */
 if (EVP_EncryptFinal_ex(ctx, *ciphertext + len, &len) != 1) {
 fprintf(stderr, "Error: Encryption final failed\n");
 free(*ciphertext);
 EVP_CIPHER_CTX_free(ctx);
 return -1;
 }
 ciphertext_len += len;

 EVP_CIPHER_CTX_free(ctx);
 return ciphertext_len;
}

/* Function: AES-256-CBC Decryption */
int aes_decrypt(unsigned char *ciphertext, int ciphertext_len,
 unsigned char *key, unsigned char *iv,
 unsigned char **plaintext) {

 EVP_CIPHER_CTX *ctx = EVP_CIPHER_CTX_new();
 if (!ctx) return -1;

 int len = 0;
 int plaintext_len = 0;

 *plaintext = malloc(ciphertext_len + AES_IV_LEN);
 if (!*plaintext) {
 EVP_CIPHER_CTX_free(ctx);
 return -1;
 }

 /* Initialize decryption operation */
 if (EVP_DecryptInit_ex(ctx, EVP_aes_256_cbc(), NULL, key, iv) != 1) {
 fprintf(stderr, "Error: Decryption init failed\n");
 free(*plaintext);
 EVP_CIPHER_CTX_free(ctx);
 return -1;
 }

 /* Decrypt the ciphertext */
 if (EVP_DecryptUpdate(ctx, *plaintext, &len, ciphertext, ciphertext_len) != 1) {
 fprintf(stderr, "Error: Decryption update failed\n");
 free(*plaintext);
 EVP_CIPHER_CTX_free(ctx);
 return -1;
 }
 plaintext_len = len;

 /* Finalize decryption (remove padding) */
 if (EVP_DecryptFinal_ex(ctx, *plaintext + len, &len) != 1) {
 fprintf(stderr, "Error: Decryption final failed\n");
 free(*plaintext);
 EVP_CIPHER_CTX_free(ctx);
 return -1;
 }
 plaintext_len += len;
 (*plaintext)[plaintext_len] = '\0';

 EVP_CIPHER_CTX_free(ctx);
 return plaintext_len;
}

/* Print buffer as hex for debugging */
void print_hex(unsigned char *data, int len, char *label) {
 printf("%s: ", label);
 for (int i = 0; i < len && i < 32; i++) {
 printf("%02x", data[i]);
 }
 if (len > 32) printf("...");
 printf("\n");
}

int main() {
 printf("=== Cloud Data Encryption: AES-256-CBC Demo ===\n\n");

 /* Simulate cloud data (e.g., S3 object) */
 const char *cloud_data = "{\"customer_id\": \"CUST-001\", \"ssn\": \"123-45-6789\"}";
 int data_len = strlen(cloud_data);

 printf("Original Data: %s\n", cloud_data);
 printf("Data Length: %d bytes\n\n", data_len);

 /* Generate encryption key (simulates KMS-managed key) */
 unsigned char encryption_key[AES_KEY_LEN];
 generate_random_bytes(encryption_key, AES_KEY_LEN);
 print_hex(encryption_key, AES_KEY_LEN, "Encryption Key");

 /* Generate IV (unique per encryption) */
 unsigned char iv[AES_IV_LEN];
 generate_random_bytes(iv, AES_IV_LEN);
 print_hex(iv, AES_IV_LEN, "Initialization Vector");

 /* Encrypt (like server-side encryption) */
 printf("\n--- Encrypting (Encryption at Rest) ---\n");
 unsigned char *encrypted_data = NULL;
 int encrypted_len = aes_encrypt(
 (unsigned char *)cloud_data, data_len,
 encryption_key, iv,
 &encrypted_data
 );

 if (encrypted_len > 0) {
 print_hex(encrypted_data, encrypted_len, "Ciphertext");
 printf("Encrypted Length: %d bytes\n", encrypted_len);
 }

 /* Decrypt (like data retrieval from cloud storage) */
 printf("\n--- Decrypting (Data Access) ---\n");
 unsigned char *decrypted_data = NULL;
 int decrypted_len = aes_decrypt(
 encrypted_data, encrypted_len,
 encryption_key, iv,
 &decrypted_data
 );

 if (decrypted_len > 0) {
 printf("Decrypted Data: %s\n", decrypted_data);
 }

 /* Demonstrate key management scenario */
 printf("\n--- Cloud KMS Simulation ---\n");
 printf("In production, encryption key would be stored in:\n");
 printf(" - AWS KMS (aws kms encrypt)\n");
 printf(" - Azure Key Vault\n");
 printf(" - GCP Cloud KMS\n");
 printf("This ensures key rotation and access control.\n");

 /* Cleanup */
 free(encrypted_data);
 free(decrypted_data);
 memset(encryption_key, 0, AES_KEY_LEN);

 return 0;
}
